export function cleanClinicalText(raw: string): string {
  return (
    raw

      /* ---------------------------------
       Remove broken encoding artifacts
    ---------------------------------- */
      .replace(/锟斤拷/g, "")

      /* ---------------------------------
       Remove control / invisible chars
    ---------------------------------- */
      .replace(/[\u0000-\u0008\u000B\u000C\u000E-\u001F]/g, "")

      /* ---------------------------------
       Normalize smart / broken quotes
    ---------------------------------- */
      .replace(/[’‘]/g, "'")
      .replace(/[“”]/g, '"')
      .replace(/[]/g, '"')

      /* ---------------------------------
       Normalize whitespace
    ---------------------------------- */
      .replace(/\r\n/g, "\n")
      .replace(/\n{3,}/g, "\n\n")
      .replace(/[ \t]+/g, " ")

      /* ---------------------------------
       Remove unsafe HTML
    ---------------------------------- */
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")

      /* ---------------------------------
       Cleanup spacing
    ---------------------------------- */
      .replace(/\s+\n/g, "\n")
      .replace(/\n\s+/g, "\n")

      /* ---------------------------------
       Final trim
    ---------------------------------- */
      .trim()
  );
}
export interface ParsedDischargeSummary {
  sections: Record<string, string>;
  references: Reference[];
}

function cleanTitle(title: string): string {
  return title
    .trim()
    .replace(/:+$/, "")
    .replace(/\s+/g, " ")
    .toLowerCase()
    .replace(/\b\w/g, (c) => c.toUpperCase());
}

function cleanSectionContent(rawTitle: string, content: string): string {
  const titleForStripping = rawTitle
    .trim()
    .replace(/:+$/, "")
    .replace(/\s+/g, " ");

  const escaped = titleForStripping.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");

  const prefixRegex = new RegExp(`^${escaped}[:\\s]*`, "i");

  return content.replace(prefixRegex, "").replace(/^\s+/, "").trim();
}

function extractCitationIds(content: string): string[] {
  const ids = new Set<string>();
  const matches = content.match(/\[T[\d,\s\-T]+\]/g) ?? [];

  for (const match of matches) {
    const inner = match.replace(/[\[\]]/g, "").trim();

    const parts = inner.split(",").map((p) => p.trim());

    for (const part of parts) {
      if (part.includes("-")) {
        const [start, end] = part.split("-");
        const startNum = parseInt(start.replace("T", ""), 10);
        const endNum = parseInt(end.replace("T", ""), 10);

        if (!isNaN(startNum) && !isNaN(endNum)) {
          for (let i = startNum; i <= endNum; i++) {
            ids.add(`T${i}`);
          }
        }
      } else if (/^T\d+$/.test(part)) {
        ids.add(part);
      }
    }
  }

  return Array.from(ids);
}

function toHttpUrl(rawPath: string): string {
  const normalized = rawPath.replace(/\\/g, "/");
  if (normalized.startsWith("http://") || normalized.startsWith("https://")) {
    return normalized;
  }
  return `http://${normalized}`;
}

function parseRawReference(raw: string): { id: string; url: string } | null {
  const trackMatch = raw.match(/Track Number:\s*(T\d+)/i);
  const sourceMatch = raw.match(/Document Source:\s*(.+)$/i);

  if (!trackMatch || !sourceMatch) {
    logger.warn("Could not parse reference", { raw });
    return null;
  }

  const id = trackMatch[1].trim();
  const rawPath = sourceMatch[1].trim();

  const cleanPath = rawPath.replace(/^\\\\/, "");
  const url = toHttpUrl(cleanPath);

  return { id, url };
}

